app.post('/api/contract/create', async (req, res) => {
  try {
    const {
      customer_name, customer_phone, address,
      service_type, size, service_date, price,
      company_name, owner_phone, admin_key,
      owner_signature,
      // 하위호환: 구버전 contractData 방식
      contractData, ownerSignature, ownerPhone,
      customerPhone, customerName, companyName, companyPhone
    } = req.body;

    // 필드 통합 (신규 개별필드 우선)
    const custName  = customer_name  || customerName  || contractData?.customerName  || '';
    const custPhone = customer_phone || customerPhone || contractData?.customerPhone || '';
    const ownerPh   = owner_phone    || ownerPhone    || '';
    const company   = company_name   || companyName   || contractData?.companyName   || '싹싹클린';
    const ownerSig  = owner_signature || ownerSignature || null;

    if (!custName || !custPhone) {
      return res.status(400).json({ error: '고객명과 연락처는 필수입니다.' });
    }

    const crypto = require('crypto');
    const token = crypto.randomBytes(20).toString('hex');

    // Supabase 저장
    const contractObj = contractData || {
      customerName: custName, customerPhone: custPhone,
      address, serviceType: service_type, size, serviceDate: service_date,
      price, companyName: company, ownerPhone: ownerPh
    };

    // contract_data에 모든 정보 포함 (테이블 컬럼 의존성 최소화)
    const fullContractData = {
      ...contractObj,
      customerName: custName,
      customerPhone: custPhone,
      companyName: company,
      ownerPhone: ownerPh,
    };
    const insertObj = {
      token,
      contract_data: fullContractData,
      owner_signature: ownerSig || null,
      status: 'pending'
    };
    // 테이블에 직접 컬럼이 있으면 추가 (없어도 에러 안 나도록 try)
    const { error } = await supabase.from('pending_contracts').insert([insertObj]);
    if (error) throw error;

    // SMS: 고객에게 서명 링크 발송
    const signUrl = `https://ssakapp.co.kr/sign.html?token=${token}`;
    const smsMsg = `[${company}] ${custName} 고객님, 계약서 서명을 요청드립니다.\n\n서명 링크:\n${signUrl}\n\n링크 유효기간 7일`;
    try {
      await sendSMSUtil(custPhone, smsMsg, `[${company}] 계약서 서명 요청`);
    } catch(smsErr) { console.log('SMS send error:', smsErr.message); }

    console.log(`계약서 생성: ${token}`);
    res.json({ success: true, token, signUrl });
  } catch (err) {
    console.error('계약서 생성 오류:', err);
    res.status(500).json({ error: '계약서 생성 오류: ' + err.message });
  }
});

